import fs from 'fs';

import { getReportDescription } from '../features';
import { createTestPlanExecution } from '../interface';
import { print } from '../utils';

import {
  getTestLabels,
  getXrayDefaultTestPlanKey,
  getMergedReportDirectory,
  getTestEnvironment,
  getTestFixVersions,
} from '../config';

import { setProxy } from '../interface/set-proxy';
import { analyseXrayError } from './analyse-xray-error';

export async function sendReport() {
  const testExecutionReport = `${getMergedReportDirectory()}/merged-output.json`;
  let testExecutionResults: JSON;
  try {
    testExecutionResults = JSON.parse(fs.readFileSync(testExecutionReport, 'utf-8')) as JSON;
  } catch (error) {
    throw new Error(`Failed to read test execution report from ${testExecutionReport}.`);
  }

  const summary = 'Test execution generated by xray-connector';
  let response: any;
  try {
    response = await createTestPlanExecution(
      summary,
      getReportDescription(),
      testExecutionResults,
      getXrayDefaultTestPlanKey(),
      getTestLabels(),
      getTestFixVersions(),
      getTestEnvironment(),
    );
  } catch (error) {
    throw new Error('Failed to send execution results to Xray.\n' + analyseXrayError(error));
  }

  // See https://stackoverflow.com/questions/30809831/update-jira-ticket-status-using-rest-api
  // to change the test execution status

  return response;
}

export async function sendReportWrapper(logOutput = true): Promise<void> {
  setProxy();
  const response = await sendReport();
  let output = '';
  output += 'Successfully imported test execution results';
  output += ' for test plan ' + getXrayDefaultTestPlanKey();
  output += ` into XRay as issue ${response.testExecIssue.key}.`; // NOSONAR
  if (logOutput) {
    print(output);
  }
}
